final:
module SR_latch (  
    input wire Inv_S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @(Inv_S or R) begin  
        if (Inv_S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (!Inv_S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end  
    end   
endmodule
